const result = $input.item.json;
const body   = $('Webhook /start').item.json.body;

if (!result.ok) {
  return [{ json: {
    ok      : false,
    error   : 'Pipeline A failed',
    details : result
  }}];
}

const memo = result.files?.memo || {};
const spec = result.files?.agentDraftSpec || {};

return [{ json: {
  ok          : true,
  account_id  : body.account_id,
  company     : body.company,
  message     : 'Pipeline A complete. Review v1 summary then POST to /approve.',
  next_step   : {
    url    : 'POST http://localhost:5678/webhook-test/approve',
    approve: { account_id: body.account_id, company: body.company, decision: 'approve' },
    reject : { account_id: body.account_id, company: body.company, decision: 'reject'  }
  },
  v1_summary: {
    company_name    : memo.company_name          || body.company,
    industry        : memo.industry_type         || 'unknown',
    services        : memo.services_supported    || [],
    business_hours  : memo.business_hours        || {},
    office_address  : memo.office_address        || null,
    emergency_def   : memo.emergency_definition  || [],
    emergency_contacts: memo.emergency_routing_rules?.contacts || [],
    after_hours     : memo.after_hours_flow_summary  || '',
    office_hours    : memo.office_hours_flow_summary || '',
    agent_name      : spec.agent_name            || 'unnamed',
    retell_agent_id : spec.retell_agent_id       || 'not created',
    asana_task      : memo.asana_task_gid        || 'not created',
    unknowns        : memo.questions_or_unknowns || []
  }
}}];

const body = $('Webhook /approve').item.json.body;
const decision = (body.decision || '').toLowerCase().trim();

if (decision !== 'approve') {
  return [{ json: {
    ok       : false,
    rejected : true,
    account_id: body.account_id,
    notes    : body.notes || 'No notes provided'
  }}];
}

// Pass through for next node
return [{ json: {
  approved   : true,
  account_id : body.account_id,
  company    : body.company,
  has_form   : !!(body.form_data && Object.keys(body.form_data).length > 0),
  form_data  : body.form_data || null,
  onboarding_path: body.onboarding_path || null
}}];

const result = $input.item.json;
const ctx    = $('Check Decision').item.json;
const memo   = result.files?.memo || {};

return [{ json: {
  ok           : result.ok,
  account_id   : ctx.account_id,
  company      : ctx.company,
  pipeline_a   : '✅ v1 created',
  pipeline_b   : result.ok ? `✅ ${result.version || 'v2'} created` : '❌ failed',
  conflicts    : result.conflicts?.length ?? 0,
  changes      : result.changes?.length   ?? 0,
  retell_agent : memo.retell_agent_id     || 'see outputs',
  asana_task   : memo.asana_task_gid      || 'see outputs',
  unknowns_remaining: memo.questions_or_unknowns || []
}}];
